import { useQuery } from '@tanstack/react-query';
import clsx from 'clsx';
import { useContext, useRef, type RefObject } from 'react';
import { FormattedMessage, useIntl } from 'react-intl';

import { XmarkIcon } from '@dynatrace/strato-icons';
import type { FilterSegment } from '@dynatrace-sdk/client-query';

import {
  clearButtonCSS,
  noBorderRadiusRight,
  segmentsSelectGridCSS,
} from './SegmentSelect.sty.js';
import { SegmentSelect } from './SegmentSelect.js';
import { ValueSelect } from './ValueSelect.js';
import { Button } from '../../../../buttons/button/Button.js';
import { useOverlayStacking } from '../../../../core/hooks/useOverlayStacking.js';
import { FormFieldMessages } from '../../../../forms/forms-core/components/form-field-messages/FormFieldMessages.js';
import { useFormFieldMessagesContext } from '../../../../forms/forms-core/hooks/useFormFieldMessagesContext.js';
import { Grid } from '../../../../layouts/grid/Grid.js';
import { Tooltip } from '../../../../overlays/tooltip/Tooltip.js';
import {
  segmentsClient,
  useSegmentsCache,
  type CachedSegment,
} from '../../contexts/SegmentsCache/SegmentsCache.js';
import {
  UISegmentsContext,
  useSegmentsUIContext,
} from '../../contexts/SegmentsUI/SegmentsUIContext.js';
import { getErrorKey } from '../../contexts/SegmentsUI/segmentValidationHelper.js';
import type { UISegment } from '../../contexts/SegmentsUI/UISegments.types.js';
import { SEGMENTSELECTOR_MESSAGES } from '../../segmentMessages.js';
import * as listStyles from '../../SegmentSelector.sty.js';

type SelectionBarProps = {
  availableSegments: CachedSegment['segment'][];
  clearable?: boolean;
  readOnly?: boolean;
  autoFocus?: boolean;
  returnFocusTo: RefObject<null | HTMLButtonElement>;
  segment?: CachedSegment;
  uiSegment: UISegment;
};

function getVariables(segment: FilterSegment | undefined) {
  if (segment?.variables && segment.variables.length > 0) {
    return segment.variables[0].values;
  }

  return undefined;
}

function getLayout(hasVariables: boolean, hasClearButton: boolean) {
  if (!hasVariables && !hasClearButton) {
    return 'no-variables-readonly';
  }

  if (!hasVariables && hasClearButton) {
    return 'no-variables';
  }

  if (hasVariables && !hasClearButton) {
    return 'full-readonly';
  }
  return 'full';
}

function getErrorMessageFromKey(
  errorKey:
    | 'unavailable'
    | 'needs-update'
    | 'needs-variables'
    | null
    | undefined,
) {
  switch (errorKey) {
    case 'unavailable':
      return SEGMENTSELECTOR_MESSAGES.unavailableSegmentError;
    case 'needs-update':
      return SEGMENTSELECTOR_MESSAGES.removedVariablesError;
    case 'needs-variables':
      return SEGMENTSELECTOR_MESSAGES.valueMissingError;
    default:
      return null;
  }
}

/**
 * Error messages for the SelectionBar component.
 * @internal
 */
export const ErrorMessages = ({ uiSegment }: { uiSegment: UISegment }) => {
  const {
    data: errorKey,
    isLoading,
    error,
  } = useQuery(
    {
      queryKey: ['errorKey', uiSegment],
      queryFn: () => getErrorKey(uiSegment),
    },
    segmentsClient.queryClient,
  );

  const { arrayIdentifierErrorIds } = useContext(UISegmentsContext);
  const hasArrayIdentifierError = arrayIdentifierErrorIds?.includes(
    uiSegment.id,
  );

  if (segmentsClient.hasAccessRights === false || isLoading || error) {
    return null;
  }

  const errorMessage = getErrorMessageFromKey(errorKey);

  return (
    <FormFieldMessages>
      {(messages) => {
        if (hasArrayIdentifierError) {
          return (
            <FormFieldMessages.Item
              validityStateKey="customError"
              variant="error"
              key="array-identifier"
            >
              <FormattedMessage
                {...SEGMENTSELECTOR_MESSAGES.arrayIdentifierError}
              />
            </FormFieldMessages.Item>
          );
        }

        if (errorKey) {
          return (
            <FormFieldMessages.Item
              validityStateKey="customError"
              variant="error"
              key={errorKey}
            >
              <FormattedMessage {...errorMessage} />
            </FormFieldMessages.Item>
          );
        }

        return messages.map((props) => {
          // If it is valueMissing error from the variable select we show a custom error message.
          if (
            props.controlId !== uiSegment.id &&
            props.validityStateKey === 'valueMissing'
          ) {
            return (
              <FormFieldMessages.Item
                key={`${props.controlId}-valueMissing`}
                {...props}
              >
                <FormattedMessage
                  {...SEGMENTSELECTOR_MESSAGES.valueMissingError}
                />
              </FormFieldMessages.Item>
            );
          }

          return (
            <FormFieldMessages.Item
              key={`${props.controlId}-${props.validityStateKey}`}
              {...props}
            />
          );
        });
      }}
    </FormFieldMessages>
  );
};

/**
 * SelectionBar component
 * @internal
 */
export const SelectionBar = (props: SelectionBarProps) => {
  const {
    availableSegments,
    clearable,
    readOnly,
    autoFocus,
    uiSegment,
    returnFocusTo,
    segment: propSegment,
  } = props;
  const intl = useIntl();
  const gridRef = useRef<HTMLDivElement | null>(null);
  const isPlaceholder = uiSegment.isPlaceholder ?? false;
  const id = uiSegment.id;
  const variables = getVariables(uiSegment);

  const { removeUISegment } = useSegmentsUIContext();
  const { state } = useFormFieldMessagesContext();
  const { getSegment } = useSegmentsCache();

  // If the segment was already fetched, we use the segment prop and don't fetch.
  // However, private segments are not listed in the available segments
  // and need to be fetched individually.
  const { data: fetchedSegment } = useQuery<CachedSegment>(
    {
      queryKey: ['getSegment', id],
      queryFn: () => getSegment(id),
      enabled:
        segmentsClient.hasAccessRights !== false &&
        !isPlaceholder &&
        propSegment === undefined,
      retryOnMount: false,
    },
    segmentsClient.queryClient,
  );

  const segment = propSegment ?? fetchedSegment;

  const showDeleteButton =
    clearable && !readOnly && segmentsClient.hasAccessRights !== false;

  const stackingContext = useOverlayStacking(undefined, 'overlay');

  return (
    <li className={listStyles.segmentSelectorListItem}>
      <Tooltip
        text={intl.formatMessage(
          SEGMENTSELECTOR_MESSAGES.unlistedSegmentTooltip,
        )}
        style={{ zIndex: Number(stackingContext.style.zIndex) + 1 }}
        disabled={!segment?.temporarilyApplied}
      >
        <Grid
          ref={gridRef}
          className={segmentsSelectGridCSS({
            layout: getLayout(
              !!segment?.segment?.variables,
              !!showDeleteButton,
            ),
          })}
        >
          <SegmentSelect
            readOnly={readOnly}
            availableSegments={availableSegments}
            segment={segment}
            id={id}
            overlayWidth={`${gridRef.current?.clientWidth}px`}
            triggerClassName={clsx({
              [noBorderRadiusRight]:
                showDeleteButton || segment?.segment?.variables,
            })}
            isPlaceholder={isPlaceholder}
            autoFocus={autoFocus}
          />
          {segment?.segment?.variables && (
            <ValueSelect
              readOnly={readOnly}
              segment={segment}
              variables={variables}
              triggerClassName={clsx({
                [noBorderRadiusRight]: clearable && !readOnly,
              })}
            />
          )}
          {showDeleteButton && (
            <Button
              onClick={() => {
                removeUISegment(id);
                returnFocusTo.current?.focus();
              }}
              color={state.showError ? 'critical' : 'neutral'}
              variant="emphasized"
              className={clearButtonCSS}
              aria-label={intl.formatMessage(
                SEGMENTSELECTOR_MESSAGES.removeSegmentButton,
              )}
              data-dt-name="Remove"
            >
              <Button.Prefix>
                <XmarkIcon />
              </Button.Prefix>
            </Button>
          )}
        </Grid>
      </Tooltip>

      <ErrorMessages uiSegment={uiSegment} />
    </li>
  );
};
